func (i Intent) Validate() error {
  var errs []error
  if err := i.Intent.Validate(); err != nil { errs = append(errs, fmt.Errorf("intent meta: %w", err)) }
  if !i.CreditAmount.IsPositive() { errs = append(errs, fmt.Errorf("credit amount must be positive")) }
  if err := i.Settlement.Validate(); err != nil { errs = append(errs, fmt.Errorf("settlement: %w", err)) }
  if s, err := i.Settlement.AsInvoiceSettlement(); err == nil && s.Currency != i.Currency {
    errs = append(errs, fmt.Errorf("settlement currency %q must match credit currency %q", s.Currency, i.Currency))
  }
  return models.NewNillableGenericValidationError(errors.Join(errs...))
}

func FeatureFiltersMatchAdvance(featureFilters []string, advanceFeatures []string) bool {
  if len(featureFilters) == 0 { return true }
  if len(advanceFeatures) == 0 { return false }
  for _, feature := range advanceFeatures {
    if lo.Contains(featureFilters, feature) { return true }
  }
  return false
}

var (
  _             Patch = (*PatchExtend)(nil)
  TriggerExtend       = stateless.Trigger("extend")
)

func (p PatchExtend) Op() PatchType              { return PatchTypeExtend }
func (p PatchExtend) Trigger() stateless.Trigger { return TriggerExtend }
func (p PatchExtend) TriggerParams() any         { return p }

func (p PatchExtend) ValidateWith(intent Intent) error {
  var errs []error
  if err := p.Validate(); err != nil { errs = append(errs, err) }
  if !p.GetNewServicePeriodTo().After(intent.ServicePeriod.To) {
    errs = append(errs, fmt.Errorf("new service period to must be greater than existing service period to"))
  }
  return models.NewNillableGenericValidationError(errors.Join(errs...))
}
